import React, { useState, useEffect, useRef } from 'react';
import { useWallet } from '../contexts/WalletContext';
import { getContract, getContractReadOnly } from '../utils/contract';
import { ethers } from 'ethers';
import { 
  MessageCircle, 
  Send, 
  Plus,
  User,
  X,
  Loader,
  CheckCircle,
  AlertCircle,
  Trash2
} from 'lucide-react';

const PrivateChats = () => {
  const { walletAddress } = useWallet();
  
  // State management
  const [contacts, setContacts] = useState([]);
  const [selectedContact, setSelectedContact] = useState(null);
  const [messages, setMessages] = useState([]);
  const [newMessage, setNewMessage] = useState('');
  const [newContactAddress, setNewContactAddress] = useState('');
  const [loading, setLoading] = useState(false);
  const [sending, setSending] = useState(false);
  const [error, setError] = useState('');
  const [sendSuccess, setSendSuccess] = useState(false);
  
  // Refs
  const messagesEndRef = useRef(null);
  const eventListenerRef = useRef(null);
  
  // localStorage key for contacts
  const CONTACT_KEY = `dechat_contacts_${walletAddress}`;

  /**
   * Load contacts from localStorage
   */
  const loadContacts = () => {
    if (!walletAddress) return;
    
    try {
      const saved = localStorage.getItem(CONTACT_KEY);
      if (saved) {
        const parsedContacts = JSON.parse(saved);
        setContacts(parsedContacts);
        console.log('✅ Loaded contacts from localStorage:', parsedContacts.length);
      }
    } catch (err) {
      console.error('❌ Failed to load contacts:', err);
    }
  };

  /**
   * Save contacts to localStorage
   */
  const saveContacts = (contactList) => {
    if (!walletAddress) return;
    
    try {
      localStorage.setItem(CONTACT_KEY, JSON.stringify(contactList));
      console.log('✅ Saved contacts to localStorage:', contactList.length);
    } catch (err) {
      console.error('❌ Failed to save contacts:', err);
    }
  };

  /**
   * Format wallet address to short version
   */
  const formatAddress = (address) => {
    if (!address) return '';
    return `${address.slice(0, 6)}...${address.slice(-4)}`;
  };

  /**
   * Format timestamp to readable time
   */
  const formatTime = (timestamp) => {
    try {
      const date = new Date(Number(timestamp) * 1000);
      return date.toLocaleTimeString('en-US', {
        hour: '2-digit',
        minute: '2-digit'
      });
    } catch {
      return '';
    }
  };

  /**
   * Check if message is from current user
   */
  const isOwnMessage = (sender) => {
    return walletAddress && sender?.toLowerCase() === walletAddress.toLowerCase();
  };

  /**
   * Scroll to bottom of messages
   */
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  /**
   * Add new contact
   */
  const addContact = () => {
    setError('');

    // Validate address
    if (!ethers.utils.isAddress(newContactAddress)) {
      setError('Invalid wallet address');
      return;
    }

    // Prevent adding own address
    if (newContactAddress.toLowerCase() === walletAddress.toLowerCase()) {
      setError('Cannot add your own address');
      return;
    }

    // Prevent duplicates
    if (contacts.some(contact => contact.toLowerCase() === newContactAddress.toLowerCase())) {
      setError('Contact already exists');
      return;
    }

    // Add to contacts
    const updatedContacts = [...contacts, newContactAddress];
    setContacts(updatedContacts);
    saveContacts(updatedContacts);
    setNewContactAddress('');
    
    console.log('✅ Contact added:', newContactAddress);
  };

  /**
   * Remove contact
   */
  const removeContact = (contactToRemove) => {
    const updatedContacts = contacts.filter(
      contact => contact.toLowerCase() !== contactToRemove.toLowerCase()
    );
    setContacts(updatedContacts);
    saveContacts(updatedContacts);
    
    // If this was the selected contact, clear selection
    if (selectedContact?.toLowerCase() === contactToRemove.toLowerCase()) {
      setSelectedContact(null);
      setMessages([]);
    }
    
    console.log('✅ Contact removed:', contactToRemove);
  };

  /**
   * Load messages between current user and selected contact
   */
  const loadMessages = async (contact) => {
    if (!contact || !walletAddress) return;

    setLoading(true);
    try {
      console.log('📥 Loading messages between:', walletAddress, 'and', contact);

      const contract = await getContractReadOnly();
      const msgs = await contract.getPrivateMessages(walletAddress, contact);

      console.log('📊 Raw messages from blockchain:', msgs?.length || 0);

      // Transform messages
      const transformedMessages = (msgs || []).map((msg, index) => ({
        id: index,
        sender: msg.sender || '',
        content: msg.content || '',
        timestamp: Number(msg.timestamp || 0)
      }));

      setMessages(transformedMessages);
      console.log('✅ Messages loaded:', transformedMessages.length);

      // Scroll to bottom
      setTimeout(scrollToBottom, 100);

    } catch (err) {
      console.error('❌ Failed to load messages:', err);
      setMessages([]);
    } finally {
      setLoading(false);
    }
  };

  /**
   * Send private message
   */
  const handleSendMessage = async (e) => {
    e.preventDefault();

    if (!newMessage.trim() || !selectedContact) {
      return;
    }

    if (!walletAddress) {
      alert('Please connect your wallet');
      return;
    }

    setSending(true);
    setSendSuccess(false);

    try {
      console.log('📤 Sending private message...');
      console.log('To:', selectedContact);
      console.log('Message:', newMessage);

      const contract = await getContract();
      const tx = await contract.sendPrivateMessage(selectedContact, newMessage.trim());

      console.log('⏳ Transaction submitted:', tx.hash);
      const receipt = await tx.wait();
      console.log('✅ Message sent successfully!', receipt.hash);

      // Immediately update UI so sender sees message
      setMessages(prev => [
        ...prev,
        {
          id: prev.length,
          sender: walletAddress,
          content: newMessage.trim(),
          timestamp: Math.floor(Date.now() / 1000)
        }
      ]);

      setNewMessage('');
      setSendSuccess(true);
      setTimeout(() => setSendSuccess(false), 3000);
      setTimeout(scrollToBottom, 100);

    } catch (err) {
      console.error('❌ Failed to send message:', err);
      
      if (err.code === 'ACTION_REJECTED') {
        alert('Transaction cancelled by user');
      } else if (err.message?.includes('insufficient funds')) {
        alert('Insufficient funds to pay gas fees');
      } else {
        alert(`Failed to send message: ${err.message || 'Unknown error'}`);
      }
    } finally {
      setSending(false);
    }
  };

  /**
   * Open chat with selected contact
   */
  const openChat = (contact) => {
    setSelectedContact(contact);
    loadMessages(contact);
  };

  /**
   * Set up real-time event listener for private messages
   */
  const setupEventListener = async () => {
    try {
      console.log('🎧 Setting up event listener for PrivateMessageSent events...');

      const contract = await getContractReadOnly();

      const listener = (from, to, content, timestamp) => {
        console.log('🔔 New private message event received!');
        console.log('From:', from, 'To:', to);

        // Check if message involves current user and selected contact
        const isRelevant = (
          (from.toLowerCase() === walletAddress.toLowerCase() || to.toLowerCase() === walletAddress.toLowerCase()) &&
          selectedContact && (
            from.toLowerCase() === selectedContact.toLowerCase() || 
            to.toLowerCase() === selectedContact.toLowerCase()
          )
        );

        if (isRelevant) {
          console.log('✅ Message is relevant, adding to UI');

          // Skip if message is from current user (already added locally)
          if (from.toLowerCase() === walletAddress.toLowerCase()) {
            console.log('ℹ️ Message is from current user, already in UI');
            return;
          }

          setMessages(prevMessages => {
            const newMsg = {
              id: prevMessages.length,
              sender: from,
              content: content,
              timestamp: Number(timestamp)
            };

            // Check for duplicates
            const exists = prevMessages.some(
              msg => msg.sender?.toLowerCase() === from?.toLowerCase() && 
                     msg.content === content && 
                     msg.timestamp === Number(timestamp)
            );

            if (exists) {
              console.log('⚠️ Message already exists, skipping duplicate');
              return prevMessages;
            }

            console.log('✅ Adding new message to UI');
            return [...prevMessages, newMsg];
          });

          setTimeout(scrollToBottom, 100);
        }
      };

      contract.on("PrivateMessageSent", listener);
      eventListenerRef.current = { contract, listener };

      console.log('✅ Event listener set up successfully');

    } catch (err) {
      console.warn('⚠️ Could not set up event listener:', err?.message);
    }
  };

  /**
   * Clean up event listener
   */
  const cleanupEventListener = () => {
    if (eventListenerRef.current) {
      const { contract, listener } = eventListenerRef.current;
      try {
        contract.off("PrivateMessageSent", listener);
        console.log('🔇 Event listener cleaned up');
      } catch (err) {
        console.warn('⚠️ Error cleaning up event listener:', err);
      }
      eventListenerRef.current = null;
    }
  };

  /**
   * Load contacts when wallet connects
   */
  useEffect(() => {
    if (walletAddress) {
      loadContacts();
    }
  }, [walletAddress]);

  /**
   * Set up event listener when component mounts
   */
  useEffect(() => {
    if (walletAddress) {
      setupEventListener();
    }

    return () => {
      cleanupEventListener();
    };
  }, [walletAddress, selectedContact]);

  /**
   * Auto-scroll when messages change
   */
  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  /**
   * Not connected state
   */
  if (!walletAddress) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center max-w-md">
          <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <MessageCircle className="w-8 h-8 text-gray-400" />
          </div>
          <h2 className="text-xl font-semibold text-gray-900 mb-2">Connect Your Wallet</h2>
          <p className="text-gray-600 mb-4">
            Please connect your wallet to access private messaging.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-full bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
      {/* Contacts Sidebar */}
      <div className="w-80 border-r border-gray-200 flex flex-col">
        <div className="p-4 border-b border-gray-200">
          <h2 className="text-lg font-semibold text-gray-900 mb-4">Private Messages</h2>
          
          {/* Add Contact Form */}
          <div className="space-y-3">
            <div className="flex space-x-2">
              <input
                type="text"
                value={newContactAddress}
                onChange={(e) => {
                  setNewContactAddress(e.target.value);
                  setError('');
                }}
                placeholder="Enter wallet address (0x...)"
                className="flex-1 px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-transparent text-sm"
              />
              <button
                onClick={addContact}
                disabled={!newContactAddress.trim()}
                className={`px-3 py-2 rounded-lg font-medium transition-colors ${
                  !newContactAddress.trim()
                    ? 'bg-gray-300 text-gray-500 cursor-not-allowed'
                    : 'bg-primary-600 hover:bg-primary-700 text-white'
                }`}
              >
                <Plus className="w-4 h-4" />
              </button>
            </div>
            {error && (
              <p className="text-sm text-red-600">{error}</p>
            )}
          </div>
        </div>

        {/* Contacts List */}
        <div className="flex-1 overflow-y-auto">
          {contacts.length === 0 ? (
            <div className="p-4 text-center text-gray-500">
              <User className="w-8 h-8 mx-auto mb-2 text-gray-400" />
              <p className="text-sm">No contacts yet</p>
              <p className="text-xs mt-1">Add a wallet address above</p>
            </div>
          ) : (
            contacts.map((contact) => (
              <div
                key={contact}
                className={`p-4 border-b border-gray-100 cursor-pointer hover:bg-gray-50 transition-colors duration-200 ${
                  selectedContact === contact ? 'bg-primary-50 border-primary-200' : ''
                }`}
              >
                <div className="flex items-center justify-between">
                  <div 
                    className="flex items-center space-x-3 flex-1"
                    onClick={() => openChat(contact)}
                  >
                    <div className="w-8 h-8 bg-primary-100 rounded-full flex items-center justify-center">
                      <User className="w-4 h-4 text-primary-600" />
                    </div>
                    <div className="flex-1">
                      <h3 className="font-medium text-gray-900 text-sm">
                        {formatAddress(contact)}
                      </h3>
                      <p className="text-xs text-gray-500">
                        {contact}
                      </p>
                    </div>
                  </div>
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      removeContact(contact);
                    }}
                    className="p-1 text-gray-400 hover:text-red-600 transition-colors"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
      </div>

      {/* Chat Area */}
      <div className="flex-1 flex flex-col">
        {activeChatId && activeChat ? (
          <>
            {/* Chat Header */}
            <div className="p-4 border-b border-gray-200">
              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-3">
                  <div className="w-10 h-10 bg-primary-100 rounded-full flex items-center justify-center">
                    <User className="w-5 h-5 text-primary-600" />
                  </div>
                  <div>
                    <h3 className="font-semibold text-gray-900">
                      {formatAddress(getOtherParticipant(activeChat))}
                    </h3>
                    <p className="text-sm text-gray-500">
                      Private conversation
                    </p>
                  </div>
                </div>
              </div>
            </div>

            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4">
              {activeChatMessages.length === 0 ? (
                <div className="flex items-center justify-center h-full">
                  <p className="text-gray-500">No messages yet. Start the conversation!</p>
                </div>
              ) : (
                activeChatMessages
                  .filter(message => !message.deletedForMe)
                  .map((message) => (
                    <div
                      key={message.id}
                      className={`flex ${isOwnMessage(message.sender) ? 'justify-end' : 'justify-start'}`}
                    >
                      <div className="relative group">
                        <div
                          className={`max-w-xs lg:max-w-md px-4 py-2 rounded-lg ${
                            message.deletedForEveryone
                              ? 'bg-gray-200 text-gray-500 italic'
                              : isOwnMessage(message.sender)
                              ? 'bg-primary-600 text-white'
                              : 'bg-gray-100 text-gray-900'
                          }`}
                          onMouseDown={() => isOwnMessage(message.sender) && !message.deletedForEveryone && handleLongPress(message.id)}
                          onMouseUp={handlePressEnd}
                          onMouseLeave={handlePressEnd}
                          onTouchStart={() => isOwnMessage(message.sender) && !message.deletedForEveryone && handleLongPress(message.id)}
                          onTouchEnd={handlePressEnd}
                        >
                          <p className="text-sm">{message.content}</p>
                          <p className={`text-xs mt-1 flex items-center ${
                            message.deletedForEveryone
                              ? 'text-gray-400'
                              : isOwnMessage(message.sender) ? 'text-primary-200' : 'text-gray-500'
                          }`}>
                            {format(new Date(message.timestamp), 'HH:mm')}
                            {isOwnMessage(message.sender) && (
                              <MessageStatusIcon status={getMessageStatus(message)} />
                            )}
                          </p>
                        </div>

                        {showDeleteMenu === message.id && isOwnMessage(message.sender) && (
                          <div className="absolute top-0 right-0 mt-2 mr-2 bg-white rounded-lg shadow-lg border border-gray-200 py-2 z-10">
                            <button
                              onClick={() => handleDeleteMessage(message.id, 'forMe')}
                              className="w-full px-4 py-2 text-left text-sm text-gray-700 hover:bg-gray-100 flex items-center space-x-2"
                            >
                              <Trash2 className="w-4 h-4" />
                              <span>Delete for Me</span>
                            </button>
                            <button
                              onClick={() => handleDeleteMessage(message.id, 'forEveryone')}
                              className="w-full px-4 py-2 text-left text-sm text-red-600 hover:bg-red-50 flex items-center space-x-2"
                            >
                              <Trash2 className="w-4 h-4" />
                              <span>Delete for Everyone</span>
                            </button>
                            <button
                              onClick={() => setShowDeleteMenu(null)}
                              className="w-full px-4 py-2 text-left text-sm text-gray-500 hover:bg-gray-100 flex items-center space-x-2"
                            >
                              <X className="w-4 h-4" />
                              <span>Cancel</span>
                            </button>
                          </div>
                        )}

                        {isOwnMessage(message.sender) && !message.deletedForEveryone && (
                          <button
                            onClick={() => setShowDeleteMenu(showDeleteMenu === message.id ? null : message.id)}
                            className="absolute top-1 right-1 opacity-0 group-hover:opacity-100 p-1 text-gray-400 hover:text-gray-600 transition-opacity duration-200"
                          >
                            <MoreVertical className="w-3 h-3" />
                          </button>
                        )}
                      </div>
                    </div>
                  ))
              )}
            </div>

            {showDeleteMenu && (
              <div 
                className="fixed inset-0 z-5" 
                onClick={() => setShowDeleteMenu(null)}
              />
            )}

            {/* Message Input */}
            <div className="p-4 border-t border-gray-200">
              <form onSubmit={handleSendMessage} className="flex space-x-4">
                <input
                  type="text"
                  value={newMessage}
                  onChange={(e) => setNewMessage(e.target.value)}
                  placeholder="Type your message..."
                  disabled={isLoading}
                  className="flex-1 input-field disabled:opacity-50"
                />
                <button
                  type="submit"
                  disabled={!newMessage.trim() || isLoading}
                  className="btn-primary flex items-center space-x-2 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {isLoading ? (
                    <>
                      <Loader2 className="w-4 h-4 animate-spin" />
                      <span>Sending...</span>
                    </>
                  ) : (
                    <>
                      <Send className="w-4 h-4" />
                      <span>Send</span>
                    </>
                  )}
                </button>
              </form>
            </div>
          </>
        ) : (
          <div className="flex-1 flex items-center justify-center">
            <div className="text-center">
              <MessageCircle className="w-12 h-12 text-gray-400 mx-auto mb-4" />
              <h3 className="text-lg font-medium text-gray-900 mb-2">
                Select a conversation
              </h3>
              <p className="text-gray-500">
                Choose a chat from the sidebar or start a new one
              </p>
            </div>
          </div>
        )}
      </div>

      {/* New Chat Modal */}
      {showNewChatModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 w-full max-w-md">
            <h3 className="text-lg font-semibold text-gray-900 mb-4">
              Start New Chat
            </h3>
            <div className="mb-4">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Wallet Address
              </label>
              <input
                type="text"
                value={newChatAddress}
                onChange={(e) => {
                  setNewChatAddress(e.target.value);
                  setError('');
                }}
                placeholder="0x..."
                className="input-field"
              />
              {error && (
                <p className="mt-2 text-sm text-red-600">{error}</p>
              )}
            </div>
            <div className="flex space-x-3">
              <button
                onClick={() => {
                  setShowNewChatModal(false);
                  setNewChatAddress('');
                  setError('');
                }}
                className="flex-1 btn-secondary"
              >
                Cancel
              </button>
              <button
                onClick={handleCreateChat}
                className="flex-1 btn-primary"
              >
                Start Chat
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Toast Notification */}
      {toast && (
        <div className="fixed bottom-4 right-4 z-50 animate-slide-up">
          <div className={`px-6 py-3 rounded-lg shadow-lg flex items-center space-x-3 ${
            toast.type === 'success' 
              ? 'bg-green-500 text-white' 
              : 'bg-red-500 text-white'
          }`}>
            {toast.type === 'success' ? (
              <CheckCheck className="w-5 h-5" />
            ) : (
              <X className="w-5 h-5" />
            )}
            <span className="font-medium">{toast.message}</span>
          </div>
        </div>
      )}
    </div>
  );
};

export default PrivateChats;
